-    /* Reactor and blocking pool are future work (bd-vhzw, bd-8575) */
+    /* Reactor: epoll on Linux, poll fallback elsewhere */
+#if defined(__linux__)
+    hooks->reactor.ctx = &g_reactor_ctx;
+#endif
